      "arguments": {
        "collection": "sam_contracts",
        "filter": {
          "renewal_date": {
            "$exists": true,
            "$lte": {
              "$date": "2025-03-31"
            }
          },
          "status": {
            "$in": ["active", "pending_renewal"]
          }
        },
        "projection": {
          "contract_id": 1,
          "publisher": 1,
          "product": 1,
          "effective_date": 1,
          "expiration_date": 1,
          "renewal_date": 1,
          "contract_value_usd": 1,
          "license_count": 1
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT publisher, product, fiscal_year, fiscal_quarter, SUM(amount_usd) AS total_spend, AVG(daily_active_seats) AS avg_daily_active_seats, COUNT(DISTINCT user_id) AS unique_users, COUNT(DISTINCT license_id) AS license_count FROM consumption_facts WHERE event_date >= '2024-01-01' AND publisher IS NOT NULL AND product IS NOT NULL GROUP BY publisher, product, fiscal_year, fiscal_quarter ORDER BY publisher, product, fiscal_year DESC, fiscal_quarter DESC"
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.aggregate",
      "arguments": {
        "collection": "sam_contracts",
        "pipeline": [
          {
            "$match": {
              "renewal_date": {
                "$exists": true,
                "$lte": {
                  "$date": "2025-03-31"
                }
              }
            }
          },
          {
            "$lookup": {
              "from": "consumption_trends",
              "let": {
                "publisher": "$publisher",
                "product": "$product"
              },
              "pipeline": [
                {
                  "$match": {
                    "$expr": {
                      "$and": [
                        {
                          "$eq": [
                            "$publisher",
                            "$$publisher"
                          ]
                        },
                        {
                          "$eq": [
                            "$product",
                            "$$product"
                          ]
                        }
                      ]
                    }
                  }
                }
              ],
              "as": "consumption_data"
            }
          },
          {
            "$addFields": {
              "days_to_renewal": {
                "$divide": [
                  {
                    "$subtract": [
                      "$renewal_date",
                      {
                        "$toDate": "2024-10-01"
                      }
                    ]
                  },
                  86400
